"""flags.py - Banderas embebidas como base64"""
import base64

FLAGS_B64 = {
    "es": "",
    "en": "",
    "zh": "",
    "ru": "",
    "fr": "",
    "de": "",
    "pt": "",
    "it": "",
}

def get_flag_pixmap(lang_code: str, w: int = 24, h: int = 16):
    """Obtener QPixmap de bandera para el idioma dado."""
    try:
        from PySide6.QtGui import QPixmap
        from PySide6.QtCore import QByteArray
        b64 = FLAGS_B64.get(lang_code, FLAGS_B64.get("es", ""))
        if not b64: return None
        data = base64.b64decode(b64)
        pm = QPixmap()
        pm.loadFromData(QByteArray(data))
        return pm.scaled(w, h)
    except Exception:
        return None
